var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"잠깐 그라운드 원에 들렀다가 엉겁결에 따라오긴 했는데…….","JPN":"グラウンド・ワンに寄ったついでになんとなくついて来たら……","ENG":"We tagged along all the way here because we happened to be in Ground One at the time of the red alert...","TWN":"剛好去了趟G1，就莫名其妙跟著一起過來……"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"처음부터 우리까지 나설 필요는 없었겠어.","JPN":"最初から俺らの出番は必要なかったようだな。","ENG":"But there was no need for us to step in, after all.","TWN":"但一開始我們就沒必要出馬吧。"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"그래. 이게 그 모더레이터란 녀석인가?","JPN":"だな。これがモデレーターってやつか？","ENG":"So, this is the Moderator?","TWN":"嘿咩，這就是那個叫仲裁者的嗎？"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"후후, 아쉽게 됐군. 이 덩치라면 내 샷건 <color=#ffd34c>그란투리스모</color>의 좋은 먹잇감이 됐을 텐데.","JPN":"フフ、残念だな。この大きさなら俺のショットガン<color=#ffd34c>グランドツアー</color>の餌にぴったりだったのに。","ENG":"Oh, bummer. This big guy would have been a good target for my shotgun, <color=#ffd34c>Grand Turismo</color>.","TWN":"呵呵，真可惜。我的霰彈槍<color=#ffd34c>格蘭多·里斯莫</color>應該會很喜歡這個大塊頭。"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"하, 이런 잔챙이 상대로 으스대긴.","JPN":"ふん、こんな雑魚相手にイキってもな。","ENG":"What, you’re making a fuss about this small fry?","TWN":"哼，這種廢鐵有什麼好說嘴的？"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"나라면 단 한 발로 끝냈어. 정확하고 깔끔하게 말이야.","JPN":"俺ならたった一発で終わらせられた。正確かつキレイにな！","ENG":"I would have finished it with a single shot. A clean shot.","TWN":"要是我，只需要一顆子彈，一顆就給它命中紅心！"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"하, 내가 조금 이해하기 어렵게 말했나? 딱 반 발로 끝냈다는 얘기였어.","JPN":"は？　俺の言い方が悪かったか？　俺なら一発でもなく半発で仕留められたって話だぞ。","ENG":"Hah, was it so difficult to understand? What I meant was I could have finished it with a single barrel.","TWN":"哼，我剛說的你是不是沒聽懂？意思就是我只需要半顆子彈啦！"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"둘이 뭘 그렇게 쑥덕거리고 있어?","JPN":"なーに二人でイチャイチャしてんだよ。","ENG":"What are you two doing, fooling around?","TWN":"你們還沒吵完嗎？"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"너희들이 떠드는 동안 이 토미 더 다이하드님은 민박집까지 알아 보고 왔다고.","JPN":"お前らが雑談している間に、このトミー・ザ・ダイハード様は泊まれる宿まで調べてきたんだぞ。","ENG":"I just found us accommodations while you were chattering away.","TWN":"在你們吵嘴的時候，我頑強·湯米都已經打聽好民宿了。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"뭐? 이렇게 사람들이 북적거리는데?","JPN":"マジか！　やったな！","ENG":"Huh? How did you do that, with so many competitors around?","TWN":"真的假的？人家都還沒吵完欸？！"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"젠장, 믿고 있었다고!","JPN":"おお、さすがだ！","ENG":"Dang, I knew I could count on you!","TWN":"該死，我就知道你可以！"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MAYA_FRONTIER_NULL_NULL","text":{"KOREA":"언니, 오빠! 이쪽이야, 이쪽!","JPN":"ニーナさん、リーさん！　こっちです、こっち！","ENG":"Nina! Lee! Over here!","TWN":"姊姊…哥哥！這裡這裡！"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"MAYA_FRONTIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NINA_FRONTIER_NULL_NULL","text":{"KOREA":"마야 쟤……. 오늘따라 평소보다 더 기운이 넘치네.","JPN":"マヤってば……今日はいつもの倍ぐらい元気だな。","ENG":"Maya seems more energetic than usual.","TWN":"瑪雅…今天比平時更有精神呢。"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"LEE_FRONTIER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NINA_FRONTIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"LEE_FRONTIER_NULL_NULL","text":{"KOREA":"그럴 만도 하지. 그렇게 좋아라 하는 하트베리인지도 여기 왔다잖아.","JPN":"無理もない。あんなに好きなハートベリーかなんかがここに来ているからな。","ENG":"No wonder. Her favorite HRT Berry is here as well, you know.","TWN":"是可以理解，畢竟她愛的愛心莓果也在這裡。"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"LEE_FRONTIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NINA_FRONTIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"MAYA_FRONTIER_NULL_NULL","text":{"KOREA":"응! 맞아! 하트베리 루미!","JPN":"うん！　ハートベリーのルミちゃん！","ENG":"Yes! Lumi of HRT Berry!","TWN":"嗯！沒錯！愛心莓果的魯米！"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"MAYA_FRONTIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MAYA_FRONTIER_NULL_NULL","text":{"KOREA":"빨리 만났으면 좋겠어. 여기다 루미 언니도 감탄할 만큼 커다란 버섯구름을 만들 거거든.","JPN":"はやく会いたいな。ここでルミちゃんがビックリするぐらいの大きな爆発を作りたいのです。","ENG":"I hope to see her soon. I’m going to make a huge mushroom cloud to impress her!","TWN":"真希望快點見面！我可以在這裡製作，讓魯米姊姊也驚嘆的巨大蕈狀雲！"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"MAYA_FRONTIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};